import io,re,tokenize,sys

FILES = [
 "src/polaris_graph/decomposer.py",
 "src/polaris_graph/audit_ir/scope_classifier_llm.py",
 "src/polaris_graph/audit_ir/template_classifier.py",
 "src/polaris_graph/domain/domain_signal.py",
 "src/polaris_graph/generator/claim_atom_extractor.py",
 "src/polaris_graph/generator/evidence_value_extractor.py",
 "src/polaris_graph/generator/summary_table.py",
]

# domain nouns the synthesis alleges are hardcoded
TERMS = ["tirzepatide","semaglutide","glp-1","glp1","hba1c","radiologist","paralegal",
 "deskilling","reskilling","call centre","call center","diabet","obesity","myeloma",
 "car-t","parkinson","4ir","artificial intelligence"," ai ","labor market","labour market",
 "oncology","cardiovascular","insulin","metformin"]

def classify(path):
    src=open(path).read()
    # Build a map of which byte ranges are STRING or COMMENT tokens
    toks=list(tokenize.generate_tokens(io.StringIO(src).readline))
    lines=src.split("\n")
    # per-line: is this line's content inside a docstring/comment?
    # Simpler: collect string-literal tokens that are DOCSTRINGS (statement-level) and comments
    comment_lines=set(); docstring_lines=set(); code_string_lines=set()
    prev_toktype=tokenize.INDENT
    for tok in toks:
        ttype,tstr,start,end,_=tok
        if ttype==tokenize.COMMENT:
            for ln in range(start[0],end[0]+1): comment_lines.add(ln)
        elif ttype==tokenize.STRING:
            # docstring == string that is its own statement (prev is NEWLINE/INDENT/DEDENT/ENCODING)
            if prev_toktype in (tokenize.NEWLINE,tokenize.NL,tokenize.INDENT,tokenize.DEDENT,tokenize.ENCODING):
                for ln in range(start[0],end[0]+1): docstring_lines.add(ln)
            else:
                for ln in range(start[0],end[0]+1): code_string_lines.add(ln)
        if ttype not in (tokenize.NL,tokenize.COMMENT):
            prev_toktype=ttype

    hits={"code":[], "docstring":[], "comment":[]}
    for i,line in enumerate(lines,1):
        ll=line.lower()
        for t in TERMS:
            if t in ll:
                if i in comment_lines and i not in code_string_lines: bucket="comment"
                elif i in docstring_lines and i not in code_string_lines: bucket="docstring"
                elif i in code_string_lines: bucket="code"
                else: bucket="code"
                hits[bucket].append((i,t,line.strip()[:90]))
                break
    return hits

